        summary = member.find('summary')
        if summary is not None:
            print('  Summary:', ET.tostring(summary, encoding='unicode').strip())
        for param in member.findall('param'):
            print('  Param:', param.get('name'), '-', (param.text or '').strip())
        returns = member.find('returns')
        if returns is not None:
            print('  Returns:', ET.tostring(returns, encoding='unicode').strip())
        print()
