import subprocess, os

# Create a small C# script to inspect the types via reflection
script = '''
using System;
using System.Reflection;

var asm = Assembly.LoadFrom(
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile) +
    "/.nuget/packages/xunit.v3.extensibility.core/3.2.2/lib/netstandard2.0/xunit.v3.core.dll");

var type = asm.GetType("Xunit.v3.BeforeAfterTestAttribute");
if (type != null)
{
    Console.WriteLine($"Type: {type.FullName}");
    Console.WriteLine($"Base: {type.BaseType}");
    foreach (var m in type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    {
        var parms = string.Join(", ", Array.ConvertAll(m.GetParameters(), p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({parms})");
    }
}
'''

os.makedirs('/tmp/xunit3inspect', exist_ok=True)
with open('/tmp/xunit3inspect/Program.cs', 'w') as f:
    f.write(script)

csproj = '''<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net8.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="xunit.v3.extensibility.core" Version="3.2.2" />
    <PackageReference Include="xunit.v3.common" Version="3.2.2" />
  </ItemGroup>
</Project>'''
with open('/tmp/xunit3inspect/xunit3inspect.csproj', 'w') as f:
    f.write(csproj)

result = subprocess.run(['dotnet', 'run', '--project', '/tmp/xunit3inspect'], capture_output=True, text=True, timeout=60)
print("STDOUT:", result.stdout)
print("STDERR:", result.stderr[-500:] if result.stderr else "")
